local function draw_op(op)
    if type(op) ~= 'table' then return end
    local k = op.k or op.op
    if k == 'clear' then
        onion.clear_display()
    elseif k == 'text' then
        onion.display_text(
            tostring(op.t or ''),
            op.x or 0,
            op.y or 0,
            { font = op.f or 'small', clear = false }
        )
    elseif k == 'lines' then
        ui.body_text(
            op.lines or {},
            op.x or 0,
            op.y or 0,
            op.lh or ui.LH_SMALL,
            op.f or 'small',
            op.w,
            op.max
        )
    elseif k == 'line' then
        onion.display_line(
            op.x1 or 0,
            op.y1 or 0,
            op.x2 or 0,
            op.y2 or 0,
            { clear = false }
        )
    elseif k == 'rect' then
        onion.display_rect(
            op.x or 0,
            op.y or 0,
            op.w or 1,
            op.h or 1,
            { clear = false, fill = op.fill == true }
        )
    end
end
function ui.render_frame(frame)
    if type(frame) ~= 'table' then return false end
    local ops = frame.ops
    if type(ops) ~= 'table' then return false end
    ui.begin_frame()
    for _, op in ipairs(ops) do
        if type(op) == 'table' and (op.k or op.op) == 'commit' then
        else
            draw_op(op)
        end
    end
    ui.end_frame()
    return true
end
return ui
end

package.preload["lib.identity"] = function(...)
